import { execFileSync } from "node:child_process";
import { mkdirSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import {
  FetchingJSONSchemaStore,
  InputData,
  JSONSchemaInput,
  quicktype,
} from "quicktype-core";

const GENERATED_NOTICE =
  "Generated by pnpm --filter @aether-agent/sdk generate:settings-types. Do not edit manually.";
const TS_HEADER = `// @generated ${GENERATED_NOTICE}\n// Source: packages/aether-project/src/aether_settings.rs via aether-settings-schema.\n\n`;

const root = resolve(import.meta.dirname, "../../..");
const generatedDir = resolve(import.meta.dirname, "../src/generated");
const schemaPath = resolve(generatedDir, "aether-settings.schema.json");
const typesPath = resolve(generatedDir, "aether-settings.ts");

const rustSchema = execFileSync(
  "cargo",
  ["run", "-q", "-p", "aether-project", "--bin", "aether-settings-schema"],
  { cwd: root, encoding: "utf8" },
);

const schema = withGeneratedComment(JSON.parse(rustSchema));
const outputs = [
  {
    path: schemaPath,
    content: formatWithPrettier(`${JSON.stringify(schema, null, 2)}\n`, "json"),
  },
  {
    path: typesPath,
    content: formatWithPrettier(await generateTypes(schema), "typescript"),
  },
];

mkdirSync(generatedDir, { recursive: true });
for (const { path, content } of outputs) writeFileSync(path, content);
console.log(`wrote ${dirname(schemaPath)}`);

function withGeneratedComment(schema) {
  const { $schema, $comment: _oldComment, ...rest } = schema;
  return { $schema, $comment: GENERATED_NOTICE, ...rest };
}

function formatWithPrettier(content, parser) {
  return execFileSync("pnpm", ["exec", "prettier", "--parser", parser], {
    cwd: root,
    input: content,
    encoding: "utf8",
  });
}

async function generateTypes(schema) {
  const schemaInput = new JSONSchemaInput(new FetchingJSONSchemaStore());

  await schemaInput.addSource({
    name: "AetherSettings",
    schema: JSON.stringify(schemaForTypeGeneration(schema)),
  });

  const inputData = new InputData();
  inputData.addInput(schemaInput);

  const { lines } = await quicktype({
    inputData,
    lang: "typescript",
    rendererOptions: {
      "just-types": "true",
      "prefer-unions": "true",
    },
  });

  return addCompatibilityAliases(`${TS_HEADER}${lines.join("\n")}\n`);
}

function schemaForTypeGeneration(schema) {
  const typeSchema = structuredClone(schema);
  typeSchema.title = "AetherSettings";

  for (const [name, definition] of Object.entries(typeSchema.$defs ?? {})) {
    if (definition && typeof definition === "object") definition.title = name;
  }

  return typeSchema;
}

function addCompatibilityAliases(content) {
  const aliases = [];

  if (content.includes("export interface MCPSourceSpecObject ")) {
    aliases.push("export type McpSourceSpec = MCPSourceSpecObject | string;");
  } else if (content.includes("export interface MCPSourceSpec ")) {
    aliases.push("export type McpSourceSpec = MCPSourceSpec;");
  }

  if (content.includes("export interface PromptSourceObject ")) {
    aliases.push("export type PromptSource = PromptSourceObject | string;");
  }

  if (content.includes("export interface RawMCPServerConfig ")) {
    aliases.push("export type RawMcpServerConfig = RawMCPServerConfig;");
  }

  if (aliases.length === 0) return content;
  return `${content.trimEnd()}\n\n${aliases.join("\n")}\n`;
}
